import React from "react";

function LoginPage() {
  return (
    <div style={styles.container}>
      
      {/* LEFT CARD */}
      <div style={styles.card}>
        
        {/* Tabs */}
        <div style={styles.tabs}>
          <span style={{ ...styles.tab, ...styles.activeTab }}>Login</span>
          <span style={styles.tab}>Register</span>
        </div>

        {/* Form */}
        <div style={styles.form}>
          <label style={styles.label}>Email</label>
          <input type="email" style={styles.input} />

          <label style={styles.label}>Password</label>
          <input type="password" style={styles.input} />

          <div style={styles.remember}>
            <input type="checkbox" />
            <span>Remember Me</span>
          </div>

          <button style={styles.button}>Login</button>

          <p style={styles.text}>
            Don’t have an account?{" "}
            <span style={styles.link}>Register</span>
          </p>
        </div>
      </div>

      {/* RIGHT SIDE */}
      <div style={styles.side}>
        <div style={styles.lockBox}>
          🔒
        </div>
        <h2 style={styles.heading}>Secure Digital Will Access</h2>
        <p style={styles.subtext}>Your data is securely stored</p>
      </div>
    </div>
  );
}

export default LoginPage;


/* ================= STYLES ================= */

const styles = {
  container: {
    all: "unset",   // 🔥 THIS RESETS EVERYTHING
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    height: "100vh",
    gap: "120px",
    background: "#eef1f5",
    fontFamily: "Segoe UI, sans-serif"
  },

  card: {
    width: "420px",
    background: "#f7f7f7",
    borderRadius: "16px",
    padding: "30px",
    boxShadow: "0 10px 30px rgba(0,0,0,0.08)"
  },

  tabs: {
    display: "flex",
    justifyContent: "space-around",
    marginBottom: "25px",
    fontSize: "18px"
  },

  tab: {
    cursor: "pointer",
    color: "#333"
  },

  activeTab: {
    color: "#1a4dff",
    borderBottom: "2px solid #1a4dff",
    paddingBottom: "4px"
  },

  form: {
    display: "flex",
    flexDirection: "column"
  },

  label: {
    fontSize: "16px",
    marginBottom: "5px",
    marginTop: "10px"
  },

  input: {
    padding: "12px",
    borderRadius: "8px",
    border: "1px solid #ccc",
    marginBottom: "10px",
    fontSize: "14px"
  },

  remember: {
    display: "flex",
    alignItems: "center",
    gap: "8px",
    marginTop: "5px"
  },

  button: {
    marginTop: "20px",
    padding: "14px",
    background: "linear-gradient(to right, #2f3cff, #001aff)",
    color: "white",
    border: "none",
    borderRadius: "8px",
    fontSize: "16px",
    cursor: "pointer"
  },

  text: {
    marginTop: "15px",
    fontSize: "14px"
  },

  link: {
    color: "#1a4dff",
    cursor: "pointer"
  },

  side: {
    textAlign: "center",
    maxWidth: "300px"
  },

  lockBox: {
    fontSize: "80px",
    marginBottom: "20px"
  },

  heading: {
    fontSize: "28px",
    marginBottom: "10px"
  },

  subtext: {
    color: "#7a7a7a",
    fontSize: "16px"
  }
};
